/**
 * Python concepts reference: sections (alphabetical), concepts (alphabetical within section).
 * Each concept has Beginner, Intermediate, and Expert explanations.
 * Terms are rendered with theme syntax-highlight class in ConceptsView.
 */

export interface ConceptEntry {
  term: string;
  beginner: string;
  intermediate: string;
  expert: string;
  /** French (when language is fr). */
  termFr?: string;
  beginnerFr?: string;
  intermediateFr?: string;
  expertFr?: string;
}

export interface ConceptSection {
  title: string;
  /** French section title (when language is fr). */
  titleFr?: string;
  concepts: ConceptEntry[];
}

